class Solution:
    def maximumMEX(self, nums):
        nums = list(nums)
        result = []
        while nums:
            full_mex = 0
            full_set = set(nums)
            while full_mex in full_set:
                full_mex += 1
            k = 1
            while True:
                seen = set(nums[:k])
                m = 0
                while m in seen:
                    m += 1
                if m == full_mex:
                    break
                k += 1
            result.append(full_mex)
            nums = nums[k:]
        return result

