var maximumMEX = function(nums) {
    const n = nums.length;
    const cap = n + 2;
    const lastSeenAt = new Int32Array(cap).fill(-1);
    const mexSuffix = new Array(n + 1).fill(0);
    let ptr = 0;
    for (let i = n - 1; i >= 0; i--) {
        const v = nums[i];
        if (v < cap) lastSeenAt[v] = i;
        while (ptr < cap && lastSeenAt[ptr] !== -1) ptr++;
        mexSuffix[i] = ptr;
    }
    const result = [];
    let i = 0;
    let segId = 0;
    const seenStamp = new Int32Array(cap).fill(-1);
    while (i < n) {
        const target = mexSuffix[i];
        segId++;
        let curPtr = 0;
        let j = i;
        while (true) {
            const v = nums[j];
            if (v < cap) seenStamp[v] = segId;
            while (curPtr < cap && seenStamp[curPtr] === segId) curPtr++;
            j++;
            if (curPtr === target) break;
        }
        result.push(target);
        i = j;
    }
    return result;
};
